        const products = [
            { id: 1, name: "Premium Wireless Headphones with Noise Cancellation", category: "Electronics", price: 790.99, originalPrice: 129.99, rating: 4.5, reviews: 2847, image: "data:image/jpeg;base64,", badge: "Best Seller", discount: 38, inStock: true, freeShipping: true },
            { id: 2, name: "Smart Watch Pro - Fitness Tracker", category: "Electronics", price: 1990.99, rating: 4.3, reviews: 1523, image: "data:image/jpeg;base64,", inStock: true, freeShipping: true },
            { id: 3, name: "Premium Cotton T-Shirt - Unisex", category: "Fashion", price: 2400.99, originalPrice: 30.99, rating: 4.0, reviews: 892, image: "data:image/jpeg;base64,", badge: "Deal", discount: 37, inStock: true, freeShipping: false },
            { id: 4, name: "Professional Running Shoes", category: "Fashion", price: 890.99, rating: 4.7, reviews: 3421, image: "data:image/jpeg;base64,", badge: "Best Seller", inStock: true, freeShipping: true },
            { id: 5, name: "Smart Coffee Maker with Timer", category: "Home", price: 490.99, rating: 4.2, reviews: 674, image: "data:image/jpeg;base64,", inStock: true, freeShipping: true },
            { id: 6, name: "Professional Blender 1200W", category: "Home", price: 399.99, originalPrice: 69.99, rating: 4.4, reviews: 1234, image: "data:image/jpeg;base64,", badge: "Deal", discount: 43, inStock: true, freeShipping: false },
            { id: 7, name: "Mystery Thriller Novel - Bestseller", category: "Books", price: 147.99, rating: 4.6, reviews: 5632, image: "data:image/jpeg;base64,", badge: "Best Seller", inStock: true, freeShipping: false },
            { id: 8, name: "Ergonomic Laptop Stand - Aluminum", category: "Electronics", price: 346.99, rating: 4.1, reviews: 432, image: "data:image/jpeg;base64,", inStock: true, freeShipping: true },
            { id: 9, name: "Premium Yoga Mat - Extra Thick", category: "Fashion", price: 294.99, rating: 4.5, reviews: 987, image: "data:image/jpeg;base64,", inStock: true, freeShipping: false },
            { id: 10, name: "Professional Chef Knife Set", category: "Home", price: 598.99, rating: 4.8, reviews: 2156, image: "data:image/jpeg;base64,", badge: "Best Seller", inStock: true, freeShipping: true },
            { id: 11, name: "Portable Bluetooth Speaker - Waterproof", category: "Electronics", price: 455.99, originalPrice: 79.99, rating: 4.4, reviews: 1876, image: "data:image/jpeg;base64,", badge: "Deal", discount: 42, inStock: true, freeShipping: true },
            { id: 12, name: "Gourmet Cookbook Collection", category: "Books", price: 196.99, rating: 4.3, reviews: 743, image: "data:image/jpeg;base64,", inStock: true, freeShipping: false }
        ];

        let cart = JSON.parse(localStorage.getItem('cart')) || [];
        let wishlist = JSON.parse(localStorage.getItem('wishlist')) || [];
        let currentUser = JSON.parse(localStorage.getItem('currentUser')) || null;
        let filteredProducts = [...products];

        // Initialize
        function init() {
            displayProducts(products);
            updateCartCount();
            updateWishlistCount();
            updateUserGreeting();
        }

        // Show Toast Notification
        function showToast(message) {
            const toast = document.getElementById('toast');
            toast.textContent = message;
            toast.classList.add('show');
            setTimeout(() => {
                toast.classList.remove('show');
            }, 3000);
        }

        // Show Loading
        function showLoading() {
            document.getElementById('loadingOverlay').classList.add('active');
        }

        function hideLoading() {
            document.getElementById('loadingOverlay').classList.remove('active');
        }

        // Display Products
        function displayProducts(productsToShow) {
            const grid = document.getElementById('productsGrid');
            grid.innerHTML = '';

            productsToShow.forEach(product => {
                const stars = '*'.repeat(Math.floor(product.rating));
                const badge = product.badge ? `<div class="product-badge ${product.badge === 'Deal' ? 'deal' : ''}">${product.badge}</div>` : '';
                const originalPriceHTML = product.originalPrice ? `<span class="original-price"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" class="bi bi-currency-rupee" viewBox="0 0 16 16">
  <path d="M4 3.06h2.726c1.22 0 2.12.575 2.325 1.724H4v1.051h5.051C8.855 7.001 8 7.558 6.788 7.558H4v1.317L8.437 14h2.11L6.095 8.884h.855c2.316-.018 3.465-1.476 3.688-3.049H12V4.784h-1.345c-.08-.778-.357-1.335-.793-1.732H12V2H4z"/>
</svg>${product.originalPrice}</span>` : '';
                const discountHTML = product.discount ? `<span class="discount-badge">-${product.discount}%</span>` : '';
                const isWishlisted = wishlist.some(item => item.id === product.id);

                const card = `
                    <div class="product-card">
                        ${badge}
                        <div class="wishlist-icon ${isWishlisted ? 'active' : ''}" onclick="toggleWishlistItem(${product.id}, event)">
                            ${isWishlisted ? '❤️' : '🤍'}
                        </div>
                        <div class="product-image-wrapper">
                            <img src="${product.image}" alt="${product.name}" class="product-image">
                            <div class="quick-view" onclick="quickView(${product.id})">Quick View</div>
                        </div>
                        <div class="product-category">${product.category}</div>
                        <div class="product-title">${product.name}</div>
                        <div class="product-rating">
                            <span>${stars}</span>
                            <span class="rating-count">${product.rating} (${product.reviews.toLocaleString()})</span>
                        </div>
                        <div class="product-price-section">
                            <span class="product-price"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" class="bi bi-currency-rupee" viewBox="0 0 16 16">
  <path d="M4 3.06h2.726c1.22 0 2.12.575 2.325 1.724H4v1.051h5.051C8.855 7.001 8 7.558 6.788 7.558H4v1.317L8.437 14h2.11L6.095 8.884h.855c2.316-.018 3.465-1.476 3.688-3.049H12V4.784h-1.345c-.08-.778-.357-1.335-.793-1.732H12V2H4z"/>
</svg>${product.price}</span>
                            ${originalPriceHTML}
                            ${discountHTML}
                        </div>
                        ${product.freeShipping ? '<div class="delivery-info">Free Delivery</div>' : '<div class="delivery-info">Delivery Charges applied</div>'}
                        <div class="product-actions">
                            <button class="add-to-cart" onclick="addToCart(${product.id}, event)">Add to Cart</button>
                            <button class="buy-now" onclick="buyNow(${product.id}, event)">Buy Now</button>
                        </div>
                    </div>
                `;
                grid.innerHTML += card;
            });

            document.getElementById('resultsCount').textContent = `${productsToShow.length} results`;
        }

        // Quick View
        function quickView(productId) {
            const product = products.find(p => p.id === productId);
            showToast(`Quick view for ${product.name}`);
        }

        // Toggle Wishlist Item
        function toggleWishlistItem(productId, event) {
            event.stopPropagation();
            const product = products.find(p => p.id === productId);
            const existingIndex = wishlist.findIndex(item => item.id === productId);

            if (existingIndex > -1) {
                wishlist.splice(existingIndex, 1);
                showToast('Removed from wishlist');
            } else {
                wishlist.push(product);
                showToast('Added to wishlist');
            }

            localStorage.setItem('wishlist', JSON.stringify(wishlist));
            updateWishlistCount();
            displayProducts(filteredProducts); // Refresh to update heart icons
        }

        // Update Wishlist Count
        function updateWishlistCount() {
            document.getElementById('wishlistCount').textContent = wishlist.length;
        }

        // Toggle Wishlist (placeholder for now)
        function toggleWishlist() {
            showToast(`You have ${wishlist.length} items in your wishlist`);
        }

        // Search Products
        function searchProducts() {
            const searchTerm = document.getElementById('searchInput').value.toLowerCase();
            if (!searchTerm.trim()) {
                showToast('Please enter a search term');
                return;
            }

            showLoading();
            setTimeout(() => {
                filteredProducts = products.filter(p =>
                    p.name.toLowerCase().includes(searchTerm) ||
                    p.category.toLowerCase().includes(searchTerm)
                );
                displayProducts(filteredProducts);
                hideLoading();
                showToast(`Found ${filteredProducts.length} products`);
            }, 500);
        }

        // Filter by Category
        function filterByCategory(category) {
            showLoading();
            setTimeout(() => {
                if (category === 'all') {
                    filteredProducts = [...products];
                } else {
                    filteredProducts = products.filter(p => p.category === category);
                }
                displayProducts(filteredProducts);
                hideLoading();
            }, 300);
        }

        // Clear Filter Sections
        function clearCategoryFilters() {
            document.querySelectorAll('.filter-option input[type="checkbox"]').forEach(cb => {
                if (['Electronics', 'Fashion', 'Home', 'Books'].includes(cb.value)) {
                    cb.checked = false;
                }
            });
            applyFilters();
        }

        function clearPriceFilters() {
            document.getElementById('minPrice').value = '';
            document.getElementById('maxPrice').value = '';
            applyFilters();
        }

        // Apply Filters
        function applyFilters() {
            showLoading();
            setTimeout(() => {
                let filtered = [...products];

                // Category filters
                const checkedCategories = [];
                document.querySelectorAll('.filter-option input[type="checkbox"]:checked').forEach(cb => {
                    if (['Electronics', 'Fashion', 'Home', 'Books'].includes(cb.value)) {
                        checkedCategories.push(cb.value);
                    }
                });

                if (checkedCategories.length > 0) {
                    filtered = filtered.filter(p => checkedCategories.includes(p.category));
                }

                // Price range filter
                const minPrice = parseFloat(document.getElementById('minPrice').value) || 0;
                const maxPrice = parseFloat(document.getElementById('maxPrice').value) || Infinity;
                filtered = filtered.filter(p => p.price >= minPrice && p.price <= maxPrice);

                // Rating filter
                const rating4 = document.getElementById('rating4').checked;
                const rating3 = document.getElementById('rating3').checked;

                if (rating4) {
                    filtered = filtered.filter(p => p.rating >= 4);
                } else if (rating3) {
                    filtered = filtered.filter(p => p.rating >= 3);
                }

                // Stock filter
                if (document.getElementById('inStock').checked) {
                    filtered = filtered.filter(p => p.inStock);
                }

                // Free shipping filter
                if (document.getElementById('freeShipping').checked) {
                    filtered = filtered.filter(p => p.freeShipping);
                }

                filteredProducts = filtered;
                displayProducts(filtered);
                hideLoading();
                showToast(`Applied filters - ${filtered.length} products found`);
            }, 300);
        }

        // Sort Products
        function sortProducts() {
            const sortValue = document.getElementById('sortSelect').value;
            let sorted = [...filteredProducts];

            showLoading();
            setTimeout(() => {
                switch (sortValue) {
                    case 'priceLow':
                        sorted.sort((a, b) => a.price - b.price);
                        break;
                    case 'priceHigh':
                        sorted.sort((a, b) => b.price - a.price);
                        break;
                    case 'rating':
                        sorted.sort((a, b) => b.rating - a.rating);
                        break;
                    case 'newest':
                        sorted.reverse();
                        break;
                }

                displayProducts(sorted);
                hideLoading();
            }, 300);
        }

        // Add to Cart
        function addToCart(productId, event) {
            event.stopPropagation();
            const product = products.find(p => p.id === productId);
            const existingItem = cart.find(item => item.id === productId);

            if (existingItem) {
                existingItem.quantity++;
            } else {
                cart.push({ ...product, quantity: 1 });
            }

            localStorage.setItem('cart', JSON.stringify(cart));
            updateCartCount();
            updateCartDisplay();
            showToast(`${product.name} added to cart!`);
        }

        // Buy Now
        function buyNow(productId, event) {
            event.stopPropagation();
            addToCart(productId, event);
            setTimeout(() => {
                toggleCart();
            }, 500);
        }

        // Update Quantity
        function updateQuantity(productId, change) {
            const item = cart.find(item => item.id === productId);
            if (item) {
                item.quantity += change;
                if (item.quantity <= 0) {
                    removeFromCart(productId);
                    return;
                }
                localStorage.setItem('cart', JSON.stringify(cart));
                updateCartCount();
                updateCartDisplay();
            }
        }

        // Remove from Cart
        function removeFromCart(productId) {
            const product = cart.find(item => item.id === productId);
            cart = cart.filter(item => item.id !== productId);
            localStorage.setItem('cart', JSON.stringify(cart));
            updateCartCount();
            updateCartDisplay();
            showToast(`${product.name} removed from cart`);
        }

        // Update Cart Count
        function updateCartCount() {
            const count = cart.reduce((sum, item) => sum + item.quantity, 0);
            document.getElementById('cartCount').textContent = count;
        }

        // Update Cart Display
        function updateCartDisplay() {
            const container = document.getElementById('cartItemsContainer');
            const totalSection = document.getElementById('cartTotalSection');

            if (cart.length === 0) {
                container.innerHTML = `
                    <div class="empty-cart">
                        <div class="empty-cart-icon">🛒</div>
                        <h3>Your cart is empty</h3>
                        <p>Add items to get started!</p>
                    </div>
                `;
                totalSection.style.display = 'none';
                return;
            }

            let html = '';
            let subtotal = 0;

            cart.forEach(item => {
                subtotal += item.price * item.quantity;
                html += `
                    <div class="cart-item">
                        <img src="${item.image}" alt="${item.name}" class="cart-item-image">
                        <div class="cart-item-details">
                            <div class="cart-item-title">${item.name}</div>
                            <div class="cart-item-price">$${item.price.toFixed(2)}</div>
                            <div class="quantity-controls">
                                <button class="qty-btn" onclick="updateQuantity(${item.id}, -1)">−</button>
                                <span class="qty-display">${item.quantity}</span>
                                <button class="qty-btn" onclick="updateQuantity(${item.id}, 1)">+</button>
                            </div>
                            <button class="cart-item-remove" onclick="removeFromCart(${item.id})">Remove</button>
                        </div>
                    </div>
                `;
            });

            container.innerHTML = html;
            document.getElementById('cartSubtotal').textContent = `$${subtotal.toFixed(2)}`;
            document.getElementById('cartTotalAmount').textContent = `$${subtotal.toFixed(2)}`;
            totalSection.style.display = 'block';
        }

        // Toggle Cart
        function toggleCart() {
            const sidebar = document.getElementById('cartSidebar');
            sidebar.classList.toggle('open');
            if (sidebar.classList.contains('open')) {
                updateCartDisplay();
            }
        }

        // Checkout
        function checkout() {
            if (!currentUser) {
                showToast('Please sign in to checkout');
                closeCart();
                setTimeout(showLogin, 300);
                return;
            }
            document.getElementById('checkoutModal').classList.add('active');
        }


        function closeCart() {
            document.getElementById('cartSidebar').classList.remove('open');
        }

        // Login Functions
        function showLogin() {
            document.getElementById('loginModal').classList.add('active');
            if (currentUser) {
                closeLogin();
                showToast('You are already signed in');
                return;
            }
            closeRegister();
        }

        function closeLogin() {
            document.getElementById('loginModal').classList.remove('active');
        }

        function showRegister() {
            document.getElementById('registerModal').classList.add('active');
            closeLogin();
        }

        function closeRegister() {
            document.getElementById('registerModal').classList.remove('active');
        }

        function handleLogin(event) {
            event.preventDefault();
            showLoading();
            const email = document.getElementById('loginEmail').value;

            setTimeout(() => {
                const user = { email, name: email.split('@')[0] };
                currentUser = user;
                localStorage.setItem('currentUser', JSON.stringify(user));

                updateUserGreeting();
                closeLogin();
                hideLoading();
                showToast(`Welcome back, ${user.name}!`);
            }, 1000);
        }

        function handleRegister(event) {
            event.preventDefault();
            showLoading();
            const name = document.getElementById('registerName').value;
            const email = document.getElementById('registerEmail').value;

            setTimeout(() => {
                const user = { email, name };
                currentUser = user;
                localStorage.setItem('currentUser', JSON.stringify(user));

                updateUserGreeting();
                closeRegister();
                hideLoading();
                showToast(`Account created! Welcome, ${user.name}!`);
            }, 1000);
        }

        function updateUserGreeting() {
            const greeting = document.getElementById('userGreeting');
            if (currentUser) {
                greeting.textContent = `Hello, ${currentUser.name}`;
            } else {
                greeting.textContent = 'Hello, Sign In';
            }
        }

        // ================= CHECKOUT FUNCTIONS =================

        function closeCheckout() {
            document.getElementById('checkoutModal').classList.remove('active');
        }

        function switchPaymentMethod() {
            const method = document.querySelector('input[name="payment"]:checked').value;

            document.getElementById('cardPayment').style.display =
                method === 'card' ? 'block' : 'none';

            document.getElementById('upiPayment').style.display =
                method === 'upi' ? 'block' : 'none';

            document.getElementById('codPayment').style.display =
                method === 'cod' ? 'block' : 'none';
        }

        function placeOrder() {
            showLoading();

            setTimeout(() => {
                hideLoading();

                showToast('Order placed successfully');

                // Clear cart
                cart = [];
                localStorage.setItem('cart', JSON.stringify(cart));
                updateCartCount();
                updateCartDisplay();

                closeCheckout();
                closeCart();
            }, 1500);
        }

        // Close checkout modal when clicking outside
        document.getElementById('checkoutModal').addEventListener('click', function (e) {
            if (e.target === this) {
                closeCheckout();
            }
        });
        init();